	}

	private void renderMyCards(List<Reclamation> list) {
		if (myReclamationsContainer == null) return;
		myReclamationsContainer.getChildren().clear();

		for (Reclamation r : list) {
			myReclamationsContainer.getChildren().add(buildMyCard(r));
		}

		refreshMyReclamationsEmptyState();
	}

	private VBox buildMyCard(Reclamation r) {
		// Card root
		VBox card = new VBox(10);
		card.getStyleClass().add("my-reclamation-card");
		card.setMaxWidth(Double.MAX_VALUE);

		// Top row: badge + title + dots
		HBox top = new HBox(10);
		top.setAlignment(Pos.CENTER_LEFT);

		Label badge = new Label(r.getStatut() == null ? "" : r.getStatut());
		badge.getStyleClass().addAll("status-badge", computeStatusClass(r.getStatut()));

		Label title = new Label(truncate(r.getTexte(), 32));
		title.getStyleClass().add("my-reclamation-title");
		HBox.setHgrow(title, Priority.ALWAYS);
		title.setMaxWidth(Double.MAX_VALUE);

		Button dots = new Button("...");
		dots.setMnemonicParsing(false);
		dots.getStyleClass().add("dots-button");
		initCardMenu(dots, r);

		top.getChildren().addAll(badge, title, dots);

		// Second row: type + date
		HBox meta = new HBox(16);
		meta.setAlignment(Pos.CENTER_LEFT);

		Label type = new Label("Type: " + (r.getType() == null ? "-" : r.getType()));
		type.getStyleClass().add("my-reclamation-meta");

		Region spacer = new Region();
		HBox.setHgrow(spacer, Priority.ALWAYS);

		String dateText = r.getDateCreation() != null ? r.getDateCreation().format(DATE_FMT) : "-";
		Label date = new Label("Créée le: " + dateText);
		date.getStyleClass().add("my-reclamation-meta");

		meta.getChildren().addAll(type, spacer, date);

		// Body (preview)
		Label body = new Label(truncate(r.getTexte(), 120));
		body.getStyleClass().add("my-reclamation-meta");
		body.setWrapText(true);

		card.getChildren().addAll(top, meta, body);
		return card;
	}

	private void initCardMenu(Button dotsButton, Reclamation r) {
		ContextMenu menu = new ContextMenu();

		MenuItem viewReplies = new MenuItem("Voir réponses");
		MenuItem edit = new MenuItem("Modifier");
		MenuItem delete = new MenuItem("Supprimer");
		menu.getItems().addAll(viewReplies, edit, new SeparatorMenuItem(), delete);

		viewReplies.setOnAction(e -> onViewReplies(r));
		edit.setOnAction(e -> onEditReclamation(r));
		delete.setOnAction(e -> onDeleteReclamation(r));

		dotsButton.setOnAction(e -> menu.show(dotsButton, javafx.geometry.Side.BOTTOM, 0, 0));
	}

	private void onViewReplies(Reclamation r) {
		try {
			FXMLLoader loader = new FXMLLoader(Objects.requireNonNull(getClass().getResource("/views/pages/reclamation_reply_dialog.fxml")));
			Parent root = loader.load();

			controllers.pages.reclamations.ReclamationReplyDialogController controller = loader.getController();
			controller.setReclamation(r);
			controller.setReadOnly(true); // utilisateur: consultation uniquement

			Stage stage = new Stage();
			stage.initModality(Modality.APPLICATION_MODAL);
			stage.setTitle("Réclamation #" + (r.getId() == null ? "-" : r.getId()));

			Scene scene = new Scene(root);
			URL dialogCss = getClass().getResource("/views/styles/reclamation-reply-dialog.css");
			if (dialogCss != null) scene.getStylesheets().add(dialogCss.toExternalForm());
			URL appCss = getClass().getResource("/views/styles/dashboard.css");
			if (appCss != null) scene.getStylesheets().add(appCss.toExternalForm());

			stage.setScene(scene);
			stage.showAndWait();
		} catch (Exception ex) {
			showError("Ouverture impossible", ex.getMessage());
		}
	}

	private void onEditReclamation(Reclamation r) {
		TextArea area = new TextArea(r.getTexte() == null ? "" : r.getTexte());
		area.setWrapText(true);
		area.setPrefRowCount(8);

		Dialog<ButtonType> dialog = new Dialog<>();
		dialog.setTitle("Modifier réclamation");
		dialog.setHeaderText("Modifier la description");
		dialog.getDialogPane().setContent(area);
		dialog.getDialogPane().getButtonTypes().addAll(ButtonType.CANCEL, ButtonType.OK);

		dialog.showAndWait().ifPresent(bt -> {
			if (bt != ButtonType.OK) return;
			String newText = area.getText() == null ? "" : area.getText().trim();
			String noSpaces = newText.replaceAll("\\s+", "");
			if (newText.isBlank() || noSpaces.length() < 10) {
				showWarning("Modification refusée", "Veuillez saisir une description d'au moins 10 caractères.");
				return;
			}
			try {
				r.setTexte(newText);
				r.setUpdatedAt(LocalDateTime.now());
				reclamationService.update(r);
				refreshMyReclamations();
				showInfo("Modification", "Réclamation modifiée avec succès.");
			} catch (SQLDataException ex) {
				showError("Modification impossible", ex.getMessage());
			} catch (Exception ex) {
				showError("Modification impossible", "Erreur inattendue: " + ex.getMessage());
			}
		});
	}

	private void onDeleteReclamation(Reclamation r) {
		Alert confirm = new Alert(Alert.AlertType.CONFIRMATION);
		confirm.setTitle("Confirmation");
		confirm.setHeaderText("Supprimer cette réclamation ?");
		confirm.setContentText("Cette action est irréversible.");
		confirm.showAndWait().ifPresent(result -> {
			if (result != javafx.scene.control.ButtonType.OK) return;
			try {
				reclamationService.delete(r);
				refreshMyReclamations();
				showInfo("Suppression", "Réclamation supprimée.");
			} catch (SQLDataException ex) {
				showError("Suppression impossible", ex.getMessage());
			} catch (Exception ex) {
				showError("Suppression impossible", "Erreur inattendue: " + ex.getMessage());
			}
		});
	}

	private String computeStatusClass(String statut) {
		String s = normalize(statut);
		boolean isNon = s.contains("non") || s.contains("en cours") || s.contains("pending") || s.contains("non tra") || s.contains("nontra");
		boolean isTraite = !isNon && (s.contains("traite") || s.contains("resolu") || s.contains("resolved") || s.contains("done"));
		return isTraite ? "traite" : "nontraite";
	}

	private static String truncate(String s, int max) {
		if (s == null) return "";
		String t = s.trim();
		if (t.length() <= max) return t;
		return t.substring(0, Math.max(0, max - 3)) + "...";
	}

	private boolean contains(String value, String search) {
		return value != null && value.toLowerCase(Locale.ROOT).contains(search);
	}

	private static String normalize(String value) {
		String s = value == null ? "" : value;
		s = s.toLowerCase(Locale.ROOT).replace("_", " ").replace("-", " ");
		s = Normalizer.normalize(s, Normalizer.Form.NFD).replaceAll("\\p{M}", "");
		while (s.contains("  ")) s = s.replace("  ", " ");
		return s.trim();
	}

	private void refreshMyReclamationsEmptyState() {
		boolean empty = myReclamationsContainer == null || myReclamationsContainer.getChildren().isEmpty();
		emptyMyReclamationsLabel.setVisible(empty);
		emptyMyReclamationsLabel.setManaged(empty);
	}

	private void showInfo(String header, String message) {
		Alert a = new Alert(Alert.AlertType.INFORMATION);
		a.setTitle("Info");
		a.setHeaderText(header);
		a.setContentText(message);
		a.showAndWait();
	}

	private void showWarning(String header, String message) {
		Alert a = new Alert(Alert.AlertType.WARNING);
		a.setTitle("Attention");
		a.setHeaderText(header);
		a.setContentText(message);
		a.showAndWait();
	}

	private void showError(String header, String message) {
		Alert a = new Alert(Alert.AlertType.ERROR);
		a.setTitle("Erreur");
		a.setHeaderText(header);
		a.setContentText(message);
		a.showAndWait();
	}
}

package controllers.pages.reclamations;

import Services.ReclamationService;
import Services.ReponseService;
import entities.Reclamation;
import entities.Reponse;
import javafx.fxml.FXML;
import javafx.scene.control.*;
import javafx.scene.layout.VBox;
import javafx.stage.Stage;

import java.time.LocalDate;
import java.time.format.DateTimeFormatter;
import java.util.ArrayList;
import java.util.List;

public class ReclamationReplyDialogController {

    @FXML private Label reclamationIdLabel;
    @FXML private TextArea reclamationTexteArea;
    @FXML private ListView<Reponse> historyList;

    @FXML private VBox replyFieldsBox;

    @FXML private Button saveBtn;
    @FXML private Button updateBtn;
    @FXML private Button deleteBtn;
    @FXML private Button cancelBtn;

    private final ReponseService reponseService = new ReponseService();
    private final ReclamationService reclamationService = new ReclamationService();

    private Reclamation reclamation;
    private Reponse selectedForEdit;

    private static final DateTimeFormatter DATE_FMT = DateTimeFormatter.ofPattern("dd/MM/yyyy");
    private static final int MIN_REPONSE_LEN = 10;

    @FXML
    public void initialize() {
        reclamationTexteArea.setEditable(false);
        reclamationTexteArea.setWrapText(true);

        historyList.setCellFactory(lv -> new ListCell<>() {
            @Override
            protected void updateItem(Reponse item, boolean empty) {
                super.updateItem(item, empty);
                if (empty || item == null) {
                    setText(null);
                } else {
                    String d = item.getDateReponse() != null ? item.getDateReponse().format(DATE_FMT) : "";
                    setText("[" + d + "] " + (item.getContenu() == null ? "" : item.getContenu()));
                }
            }
        });

        historyList.setOnMouseClicked(e -> {
            if (e.getClickCount() == 2 && historyList.getSelectionModel().getSelectedItem() != null) {
                selectedForEdit = historyList.getSelectionModel().getSelectedItem();
                fillEditField(selectedForEdit);
            }
        });

        addReplyField();
        updateBtn.setDisable(true);
        deleteBtn.setDisable(true);
    }

    public void setReclamation(Reclamation reclamation) {
        this.reclamation = reclamation;
        reclamationIdLabel.setText(reclamation.getId() != null ? String.valueOf(reclamation.getId()) : "-");
        reclamationTexteArea.setText(reclamation.getTexte() != null ? reclamation.getTexte() : "");
        loadHistory();
    }

    @FXML
    private void onAddField() {
        addReplyField();
    }

    private void addReplyField() {
        TextArea ta = new TextArea();
        ta.setPromptText("Votre reponse...");
        ta.setWrapText(true);
        ta.setPrefRowCount(3);

        VBox wrapper = new VBox(6);
        wrapper.getChildren().add(ta);
        replyFieldsBox.getChildren().add(wrapper);
    }

    private void fillEditField(Reponse rep) {
        if (rep == null) return;

        if (replyFieldsBox.getChildren().isEmpty()) {
            addReplyField();
        }

        VBox wrapper = (VBox) replyFieldsBox.getChildren().get(0);
        TextArea ta = null;
        for (var child : wrapper.getChildren()) {
            if (child instanceof TextArea t) {
                ta = t;
                break;
            }
        }

        if (ta != null) {
            ta.setText(rep.getContenu() != null ? rep.getContenu() : "");
            ta.requestFocus();
        }

        updateBtn.setDisable(false);
        deleteBtn.setDisable(false);
    }

    private void loadHistory() {
        if (reclamation == null || reclamation.getId() == null) return;
        try {
            List<Reponse> reps = reponseService.getByReclamationId(reclamation.getId());
            historyList.getItems().setAll(reps);
        } catch (Exception e) {
            historyList.getItems().clear();
        }
    }

    private void markReclamationTraite() {
        if (reclamation == null || reclamation.getId() == null) return;
        try {
            // Update only statut to avoid failing because of other columns
            reclamationService.updateStatutById(reclamation.getId(), "Traitée");
            reclamation.setStatut("Traitée");
        } catch (Exception ignored) {
        }
    }

    private void syncStatutWithReponses() {
        if (reclamation == null || reclamation.getId() == null) return;
        try {
            List<Reponse> reps = reponseService.getByReclamationId(reclamation.getId());
            boolean hasReps = reps != null && !reps.isEmpty();

            String target = hasReps ? "Traitée" : "Non traitée";
            reclamationService.updateStatutById(reclamation.getId(), target);
            reclamation.setStatut(target);
        } catch (Exception ignored) {
        }
    }

    @FXML
    private void onSave() {
        if (reclamation == null || reclamation.getId() == null) {
            showError("Reclamation invalide", "Aucun ID.");
            return;
        }

        List<String> contenus = new ArrayList<>();
        for (var node : replyFieldsBox.getChildren()) {
            if (node instanceof VBox v) {
                for (var child : v.getChildren()) {
                    if (child instanceof TextArea ta) {
                        String txt = ta.getText() != null ? ta.getText().trim() : "";
                        if (!txt.isEmpty()) contenus.add(txt);
                    }
                }
            }
        }

        for (String c : contenus) {
            if (c.length() < MIN_REPONSE_LEN) {
                showError("Validation", "La reponse doit contenir au moins " + MIN_REPONSE_LEN + " caracteres.");
                return;
            }
        }


        if (contenus.isEmpty()) {
            syncStatutWithReponses();
            close();
            return;
        }

        try {
            for (String c : contenus) {
                Reponse r = new Reponse();
                r.setReclamationId(reclamation.getId());
                r.setContenu(c);
                r.setDateReponse(LocalDate.now());
                reponseService.add(r);
            }

            markReclamationTraite();

            close();
        } catch (Exception e) {
            showError("Enregistrement impossible", e.getMessage());
        }
    }

    @FXML
    private void onUpdate() {
        if (selectedForEdit == null || selectedForEdit.getId() == null) {
            showError("Edition", "Veuillez selectionner une reponse a modifier (double clic).");
            return;
        }

        if (replyFieldsBox.getChildren().isEmpty()) {
            showError("Edition", "Aucun champ de saisie.");
            return;
        }

        VBox wrapper = (VBox) replyFieldsBox.getChildren().get(0);
        TextArea ta = null;
        for (var child : wrapper.getChildren()) {
            if (child instanceof TextArea t) {
                ta = t;
                break;
            }
        }
        if (ta == null) {
            showError("Edition", "Champ introuvable.");
            return;
        }

        String newText = ta.getText() == null ? "" : ta.getText().trim();
        if (newText.isEmpty()) {
            showError("Validation", "La reponse ne peut pas etre vide.");
            return;
        }

        if (newText.length() < MIN_REPONSE_LEN) {
            showError("Validation", "La reponse doit contenir au moins " + MIN_REPONSE_LEN + " caracteres.");
            return;
        }

        try {
            selectedForEdit.setContenu(newText);
            selectedForEdit.setDateReponse(LocalDate.now());
            reponseService.update(selectedForEdit);
            loadHistory();

            markReclamationTraite();

            selectedForEdit = null;
            updateBtn.setDisable(true);
            ta.clear();
        } catch (Exception e) {
            showError("Modification impossible", e.getMessage());
        }
    }

    @FXML
    private void onDeleteReponse() {
        Reponse selected = historyList.getSelectionModel().getSelectedItem();
        if (selected == null || selected.getId() == null) {
            showError("Suppression", "Veuillez selectionner une reponse a supprimer.");
            return;
        }

        ButtonType deleteButton = new ButtonType("Supprimer", ButtonBar.ButtonData.OK_DONE);
        ButtonType cancelButton = new ButtonType("Annuler", ButtonBar.ButtonData.CANCEL_CLOSE);
        Alert confirm = new Alert(Alert.AlertType.CONFIRMATION, "", deleteButton, cancelButton);
        confirm.setTitle("Confirmer");
        confirm.setHeaderText("Supprimer cette reponse ?");
        confirm.setContentText("Cette action est irreversible.");

        if (confirm.showAndWait().orElse(cancelButton) != deleteButton) return;

        try {
            reponseService.deleteById(selected.getId());
            loadHistory();


            syncStatutWithReponses();

            historyList.getSelectionModel().clearSelection();

            // reset edit mode
            selectedForEdit = null;
            updateBtn.setDisable(true);
            deleteBtn.setDisable(true);
        } catch (Exception e) {
            showError("Suppression impossible", e.getMessage());
        }
    }

    @FXML
    private void onCancel() {
        close();
    }

    private void close() {
        Stage stage = (Stage) cancelBtn.getScene().getWindow();
        stage.close();
    }

    private void showError(String title, String message) {
        Alert a = new Alert(Alert.AlertType.ERROR);
        a.setTitle(title);
        a.setHeaderText(title);
        a.setContentText(message);
        a.showAndWait();
    }
}

package controllers.pages.reclamations;

import Services.ReclamationService;
import Services.ReponseService;
import entities.Reclamation;
import entities.Reponse;
import javafx.fxml.FXML;
import javafx.scene.control.*;
import javafx.scene.layout.VBox;
import javafx.stage.Stage;

import java.time.LocalDate;
import java.time.format.DateTimeFormatter;
import java.util.ArrayList;
import java.util.List;

public class ReclamationReplyDialogController {

    @FXML private Label reclamationIdLabel;
    @FXML private TextArea reclamationTexteArea;
    @FXML private ListView<Reponse> historyList;

    @FXML private VBox replyFieldsBox;

    @FXML private Button saveBtn;
    @FXML private Button updateBtn;
    @FXML private Button deleteBtn;
    @FXML private Button cancelBtn;

    private final ReponseService reponseService = new ReponseService();
    private final ReclamationService reclamationService = new ReclamationService();

    private Reclamation reclamation;
    private Reponse selectedForEdit;

    private boolean readOnly = false;

    private static final DateTimeFormatter DATE_FMT = DateTimeFormatter.ofPattern("dd/MM/yyyy");
    private static final int MIN_REPONSE_LEN = 10;

    @FXML
    public void initialize() {
        reclamationTexteArea.setEditable(false);
        reclamationTexteArea.setWrapText(true);

        historyList.setCellFactory(lv -> new ListCell<>() {
            @Override
            protected void updateItem(Reponse item, boolean empty) {
                super.updateItem(item, empty);
                if (empty || item == null) {
                    setText(null);
                } else {
                    String d = item.getDateReponse() != null ? item.getDateReponse().format(DATE_FMT) : "";
                    setText("[" + d + "] " + (item.getContenu() == null ? "" : item.getContenu()));
                }
            }
        });

        historyList.setOnMouseClicked(e -> {
            if (readOnly) return;
            if (e.getClickCount() == 2 && historyList.getSelectionModel().getSelectedItem() != null) {
                selectedForEdit = historyList.getSelectionModel().getSelectedItem();
                fillEditField(selectedForEdit);
            }
        });

        addReplyField();
        updateBtn.setDisable(true);
        deleteBtn.setDisable(true);
    }

    public void setReclamation(Reclamation reclamation) {
        this.reclamation = reclamation;
        reclamationIdLabel.setText(reclamation.getId() != null ? String.valueOf(reclamation.getId()) : "-");
        reclamationTexteArea.setText(reclamation.getTexte() != null ? reclamation.getTexte() : "");
        loadHistory();
    }

    /**
     * Mode lecture seule: l'utilisateur voit uniquement les réponses existantes.
     * - cache la zone de saisie
     * - désactive les actions d'édition
     */
    public void setReadOnly(boolean readOnly) {
        this.readOnly = readOnly;

        if (replyFieldsBox != null) {
            replyFieldsBox.setManaged(!readOnly);
            replyFieldsBox.setVisible(!readOnly);
        }
        if (saveBtn != null) saveBtn.setManaged(!readOnly);
        if (saveBtn != null) saveBtn.setVisible(!readOnly);

        if (updateBtn != null) updateBtn.setManaged(!readOnly);
        if (updateBtn != null) updateBtn.setVisible(!readOnly);
        if (updateBtn != null) updateBtn.setDisable(true);

        if (deleteBtn != null) deleteBtn.setManaged(!readOnly);
        if (deleteBtn != null) deleteBtn.setVisible(!readOnly);
        if (deleteBtn != null) deleteBtn.setDisable(true);

        if (reclamationTexteArea != null) reclamationTexteArea.setEditable(false);
    }

    @FXML
    private void onAddField() {
        addReplyField();
    }

    private void addReplyField() {
        TextArea ta = new TextArea();
        ta.setPromptText("Votre reponse...");
        ta.setWrapText(true);
        ta.setPrefRowCount(3);

        VBox wrapper = new VBox(6);
        wrapper.getChildren().add(ta);
        replyFieldsBox.getChildren().add(wrapper);
    }

    private void fillEditField(Reponse rep) {
        if (rep == null) return;

        if (replyFieldsBox.getChildren().isEmpty()) {
            addReplyField();
        }

        VBox wrapper = (VBox) replyFieldsBox.getChildren().get(0);
        TextArea ta = null;
        for (var child : wrapper.getChildren()) {
            if (child instanceof TextArea t) {
                ta = t;
                break;
            }
        }

        if (ta != null) {
            ta.setText(rep.getContenu() != null ? rep.getContenu() : "");
            ta.requestFocus();
        }

        updateBtn.setDisable(false);
        deleteBtn.setDisable(false);
    }

    private void loadHistory() {
        if (reclamation == null || reclamation.getId() == null) return;
        try {
            List<Reponse> reps = reponseService.getByReclamationId(reclamation.getId());
            historyList.getItems().setAll(reps);
        } catch (Exception e) {
            historyList.getItems().clear();
        }
    }

    private void markReclamationTraite() {
        if (reclamation == null || reclamation.getId() == null) return;
        try {
            // Update only statut to avoid failing because of other columns
            reclamationService.updateStatutById(reclamation.getId(), "Traitée");
            reclamation.setStatut("Traitée");
        } catch (Exception ignored) {
        }
    }

    private void syncStatutWithReponses() {
        if (reclamation == null || reclamation.getId() == null) return;
        try {
            List<Reponse> reps = reponseService.getByReclamationId(reclamation.getId());
            boolean hasReps = reps != null && !reps.isEmpty();

            String target = hasReps ? "Traitée" : "Non traitée";
            reclamationService.updateStatutById(reclamation.getId(), target);
            reclamation.setStatut(target);
        } catch (Exception ignored) {
        }
    }

    @FXML
    private void onSave() {
        if (reclamation == null || reclamation.getId() == null) {
            showError("Reclamation invalide", "Aucun ID.");
            return;
        }

        List<String> contenus = new ArrayList<>();
        for (var node : replyFieldsBox.getChildren()) {
            if (node instanceof VBox v) {
                for (var child : v.getChildren()) {
                    if (child instanceof TextArea ta) {
                        String txt = ta.getText() != null ? ta.getText().trim() : "";
                        if (!txt.isEmpty()) contenus.add(txt);
                    }
                }
            }
        }

        for (String c : contenus) {
            if (c.length() < MIN_REPONSE_LEN) {
                showError("Validation", "La reponse doit contenir au moins " + MIN_REPONSE_LEN + " caracteres.");
                return;
            }
        }


        if (contenus.isEmpty()) {
            syncStatutWithReponses();
            close();
            return;
        }

        try {
            for (String c : contenus) {
                Reponse r = new Reponse();
                r.setReclamationId(reclamation.getId());
                r.setContenu(c);
                r.setDateReponse(LocalDate.now());
                reponseService.add(r);
            }

            markReclamationTraite();

            close();
        } catch (Exception e) {
            showError("Enregistrement impossible", e.getMessage());
        }
    }

    @FXML
    private void onUpdate() {
        if (selectedForEdit == null || selectedForEdit.getId() == null) {
            showError("Edition", "Veuillez selectionner une reponse a modifier (double clic).");
            return;
        }

        if (replyFieldsBox.getChildren().isEmpty()) {
            showError("Edition", "Aucun champ de saisie.");
            return;
        }

        VBox wrapper = (VBox) replyFieldsBox.getChildren().get(0);
        TextArea ta = null;
        for (var child : wrapper.getChildren()) {
            if (child instanceof TextArea t) {
                ta = t;
                break;
            }
        }
        if (ta == null) {
            showError("Edition", "Champ introuvable.");
            return;
        }

        String newText = ta.getText() == null ? "" : ta.getText().trim();
        if (newText.isEmpty()) {
            showError("Validation", "La reponse ne peut pas etre vide.");
            return;
        }

        if (newText.length() < MIN_REPONSE_LEN) {
            showError("Validation", "La reponse doit contenir au moins " + MIN_REPONSE_LEN + " caracteres.");
            return;
        }

        try {
            selectedForEdit.setContenu(newText);
            selectedForEdit.setDateReponse(LocalDate.now());
            reponseService.update(selectedForEdit);
            loadHistory();

            markReclamationTraite();

            selectedForEdit = null;
            updateBtn.setDisable(true);
            ta.clear();
        } catch (Exception e) {
            showError("Modification impossible", e.getMessage());
        }
    }

    @FXML
    private void onDeleteReponse() {
        Reponse selected = historyList.getSelectionModel().getSelectedItem();
        if (selected == null || selected.getId() == null) {
            showError("Suppression", "Veuillez selectionner une reponse a supprimer.");
            return;
        }

        ButtonType deleteButton = new ButtonType("Supprimer", ButtonBar.ButtonData.OK_DONE);
        ButtonType cancelButton = new ButtonType("Annuler", ButtonBar.ButtonData.CANCEL_CLOSE);
        Alert confirm = new Alert(Alert.AlertType.CONFIRMATION, "", deleteButton, cancelButton);
        confirm.setTitle("Confirmer");
        confirm.setHeaderText("Supprimer cette reponse ?");
        confirm.setContentText("Cette action est irreversible.");

        if (confirm.showAndWait().orElse(cancelButton) != deleteButton) return;

        try {
            reponseService.deleteById(selected.getId());
            loadHistory();


            syncStatutWithReponses();

            historyList.getSelectionModel().clearSelection();

            // reset edit mode
            selectedForEdit = null;
            updateBtn.setDisable(true);
            deleteBtn.setDisable(true);
        } catch (Exception e) {
            showError("Suppression impossible", e.getMessage());
        }
    }

    @FXML
    private void onCancel() {
        close();
    }

    private void close() {
        Stage stage = (Stage) cancelBtn.getScene().getWindow();
        stage.close();
    }

    private void showError(String title, String message) {
        Alert a = new Alert(Alert.AlertType.ERROR);
        a.setTitle(title);
        a.setHeaderText(title);
        a.setContentText(message);
        a.showAndWait();
    }
}

package entities;

import java.time.LocalDate;
import java.time.LocalDateTime;

public class Personne {
    private Integer id;
    private String photoProfil;
    private String resetToken;
    private LocalDateTime resetTokenExpires;
    private String nom;
    private String prenom;
    private LocalDate dateNaissance;
    private String email;
    private String mdp;
    private String role;
    private String statut;
    private LocalDate dateInscription;
    private String numTel;
    private String ville;
    private String biographie;
    private String specialite;
    private String centreInteret;
    private String photoReferencePath;

    // Legacy field kept for compatibility with existing ServicePersonne.
    private Integer age;

    public Personne() {
    }

    public Personne(String nom, String prenom, Integer age) {
        this.nom = nom;
        this.prenom = prenom;
        this.age = age;
    }

    public Integer getId() {
        return id;
    }

    public void setId(Integer id) {
        this.id = id;
    }

    public String getPhotoProfil() {
        return photoProfil;
    }

    public void setPhotoProfil(String photoProfil) {
        this.photoProfil = photoProfil;
    }

    public String getResetToken() {
        return resetToken;
    }

    public void setResetToken(String resetToken) {
        this.resetToken = resetToken;
    }

    public LocalDateTime getResetTokenExpires() {
        return resetTokenExpires;
    }

    public void setResetTokenExpires(LocalDateTime resetTokenExpires) {
        this.resetTokenExpires = resetTokenExpires;
    }

    public String getNom() {
        return nom;
    }

    public void setNom(String nom) {
        this.nom = nom;
    }

    public String getPrenom() {
        return prenom;
    }

    public void setPrenom(String prenom) {
        this.prenom = prenom;
    }

    public LocalDate getDateNaissance() {
        return dateNaissance;
    }

    public void setDateNaissance(LocalDate dateNaissance) {
        this.dateNaissance = dateNaissance;
    }

    public String getEmail() {
        return email;
    }

    public void setEmail(String email) {
        this.email = email;
    }

    public String getMdp() {
        return mdp;
    }

    public void setMdp(String mdp) {
        this.mdp = mdp;
    }

    public String getRole() {
        return role;
    }

    public void setRole(String role) {
        this.role = role;
    }

    public String getStatut() {
        return statut;
    }

    public void setStatut(String statut) {
        this.statut = statut;
    }

    public LocalDate getDateInscription() {
        return dateInscription;
    }

    public void setDateInscription(LocalDate dateInscription) {
        this.dateInscription = dateInscription;
    }

    public String getNumTel() {
        return numTel;
    }

    public void setNumTel(String numTel) {
        this.numTel = numTel;
    }

    public String getVille() {
        return ville;
    }

    public void setVille(String ville) {
        this.ville = ville;
    }

    public String getBiographie() {
        return biographie;
    }

    public void setBiographie(String biographie) {
        this.biographie = biographie;
    }

    public String getSpecialite() {
        return specialite;
    }

    public void setSpecialite(String specialite) {
        this.specialite = specialite;
    }

    public String getCentreInteret() {
        return centreInteret;
    }

    public void setCentreInteret(String centreInteret) {
        this.centreInteret = centreInteret;
    }

    public String getPhotoReferencePath() {
        return photoReferencePath;
    }

    public void setPhotoReferencePath(String photoReferencePath) {
        this.photoReferencePath = photoReferencePath;
    }

    public Integer getAge() {
        return age;
    }

    public void setAge(Integer age) {
        this.age = age;
    }

    @Override
    public String toString() {
        return "Personne{" +
                "id=" + id +
                ", nom='" + nom + '\'' +
                ", prenom='" + prenom + '\'' +
                ", email='" + email + '\'' +
                ", role='" + role + '\'' +
                ", statut='" + statut + '\'' +
                '}';
    }
}

